-- ============================================================
-- Q1: Searchable Product Listing UI
-- slug: searchable-product-listing-ui | category: frontend | difficulty: easy
-- rubric dimensions: 5
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_001',
    'system',
    'Searchable Product Listing UI',
    'searchable-product-listing-ui',
    'Junior Frontend Engineer interview. Scaffold a product listing page from scratch with search, multi-select filters, and sort. Senior signal: clean component composition, derived state, and accessible UX.',
    '# Searchable Product Listing UI

Build a product listing page that shoppers can search, filter, and sort.
Start from an empty directory — scaffold the project yourself in React
(or Vue / Svelte if you prefer), and define the product data inline in
your code (~50 items is fine; we care about your UI, not your data).

## What to build

A single page with:

1. A search input that filters products by name (case-insensitive).
2. A multi-select category filter — checkboxes for each category present
   in the data.
3. A sort control with options: `Name (A → Z)`, `Name (Z → A)`,
   `Price (low → high)`, `Price (high → low)`.
4. A product list (or grid) showing name, category, price.
5. A clear empty state when nothing matches.
6. A "Reset filters" button that returns to the initial view.

Each product should have at least: `id`, `name`, `category`, `price`.

## What we care about

- The UI feels right: search is responsive, the layout doesn''t shift
  jankily, the empty state is clear.
- Combinations work: search + categories + sort can be active
  simultaneously, and the result reflects all three.
- The code is shaped so a teammate could add a "price range" filter in
  an afternoon without rewriting yours.

## Out of scope

- A backend, real API, auth, persistence.
- A design system; basic CSS or one utility framework is fine.
- Tests, though if you write one or two we will read them.
',
    'easy',
    'frontend',
    '["react", "frontend", "state-management", "accessibility"]',
    60,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Functional Correctness", "weight": 10, "description": "All controls work and compose without bugs. **2/10**: Renders the list but search or filter doesn''t update results. **5/10**: Search and filter work individually but combining them produces wrong results, or sort breaks under a filter. **8/10**: Search + filter + sort all combine correctly; reset returns to initial state. **10/10**: Above + empty state, deselect-all behavior, and edge cases (special characters in search, products with no category) handled."}, {"name": "Component Composition", "weight": 8, "description": "Components have clear responsibilities and are reusable. **2/10**: One mega-component holds all state and JSX. **5/10**: Split into SearchBar / ProductList / ProductCard, but state lives in the wrong place (prop drilling, lifted too high or too low). **8/10**: Clean separation, state lifted to the right level, no prop drilling more than one layer. **10/10**: A reusable generic pattern emerges (e.g., a generic <FilterGroup>), and a teammate could add a price filter by composing existing pieces."}, {"name": "State and Performance", "weight": 7, "description": "State updates are predictable and re-renders are bounded. **2/10**: Direct state mutation, or filtered list re-computed in JSX every render with no memoization. **5/10**: useState + useEffect work, but every keystroke triggers a full re-render of every card. **8/10**: Filtered/sorted list memoized; debounced search; no unnecessary re-renders of unchanged cards. **10/10**: Above + handles rapid keystroke races so a slower in-flight computation cannot overwrite the latest result."}, {"name": "UX Polish", "weight": 6, "description": "The page feels finished. **2/10**: Works but feels unfinished \u2014 no debounce, jumpy layout, no feedback on actions. **5/10**: Loading-ish feel, basic responsive layout, search debounced. **8/10**: Smooth interactions, keyboard navigation, focus restored after filter changes, looks acceptable on mobile. **10/10**: Above + accessibility (labeled inputs, ARIA where needed, screen-reader-friendly), result count announced."}, {"name": "Code Quality", "weight": 5, "description": "Code is readable and consistent. **2/10**: Inconsistent naming, dead code, console logs, no types. **5/10**: Readable; basic types or PropTypes; reasonable file organization. **8/10**: Consistent style, meaningful names, well-typed props, no orphan code. **10/10**: Above + comments only where the reasoning is non-obvious; clear file structure that scales to more filters."}]}',
    NULL,
    3.0,
    1,
    1
);

-- ============================================================
-- Q2: Offline-First Notes App
-- slug: offline-first-notes-app | category: mobile | difficulty: easy
-- rubric dimensions: 5
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_002',
    'system',
    'Offline-First Notes App',
    'offline-first-notes-app',
    'Junior Mobile Engineer interview. Initialize a new React Native or Flutter project and ship a notes app that survives force-quit, fakes sync state visibly, and feels native on the keyboard.',
    '# Offline-First Notes App

Build a tiny notes app for a mobile-first audience. The app must work
without a network. Initialize a new React Native (or Flutter) project
from scratch — you may use the framework''s standard CLI to bootstrap
the app shell; everything else is yours to write.

## What to build

1. A list screen showing all notes (title + first line preview).
2. A detail screen for viewing / editing a single note.
3. Create, edit, delete operations.
4. Notes persist across app restarts (local storage / SQLite / file).
5. A search bar that filters by title or body.
6. A sync indicator at the top of the list:
   - **Online** — fake a 1s delay then mark all notes "synced".
   - **Offline** — show unsynced notes with a clear visual marker.
   - Toggle online/offline with a button in the header so we can test it
     in the simulator.

## What we care about

- The app survives a force-quit without losing data.
- The sync indicator reflects reality, not a static color.
- Typing in a long note stays smooth; the UI doesn''t block on storage.

## Out of scope

- A real backend or real sync — the network state is faked.
- Authentication or multi-user.
- Push notifications.
',
    'easy',
    'mobile',
    '["mobile", "react-native", "offline", "persistence"]',
    60,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "CRUD Correctness", "weight": 10, "description": "Create / read / update / delete all work and survive a restart. **2/10**: Can add notes but edit or delete is broken. **5/10**: All CRUD works in memory; lost on app restart. **8/10**: Persists across restarts; edit and delete operate on the right note. **10/10**: Above + handles empty notes, very long bodies, duplicate IDs, and concurrent edits across two screens."}, {"name": "Offline Persistence", "weight": 8, "description": "Writes are durable and survive failures. **2/10**: No persistence \u2014 refresh loses everything. **5/10**: Saves to AsyncStorage / equivalent on every change, but no error handling. **8/10**: Atomic writes (or batched), failures surfaced to the user, no silent data loss. **10/10**: Above + handles storage-quota failures, has a clear migration path for schema changes."}, {"name": "Sync UX", "weight": 7, "description": "The user can always tell which notes are saved and which are not. **2/10**: No indication of sync state. **5/10**: A static online/offline badge with no per-note status. **8/10**: Per-note sync status (pending / synced / failed) with a retry path. **10/10**: Optimistic UI \u2014 typing never blocks on the fake network call; failed syncs queue and retry on reconnect."}, {"name": "Mobile UX", "weight": 6, "description": "It feels like a mobile app, not a port of a web page. **2/10**: Looks like a web page; layout breaks when the keyboard opens. **5/10**: Uses platform primitives (FlatList, TextInput) but the keyboard covers the editing area. **8/10**: Keyboard avoidance, swipe-to-delete or long-press, smooth list scrolling on 1000 items. **10/10**: Above + light/dark mode, dynamic font sizing for accessibility, sensible empty state."}, {"name": "Code Quality and Layering", "weight": 5, "description": "Storage and sync are separable from the screens. **2/10**: All logic crammed into screen components. **5/10**: Separated into screens + reusable components, but storage calls scattered throughout. **8/10**: Storage and sync abstracted behind a hook or service that screens consume; swappable. **10/10**: Above + a small test or smoke script for the storage layer; types or PropTypes consistent."}]}',
    NULL,
    3.0,
    1,
    1
);

-- ============================================================
-- Q3: Bookshelf REST API
-- slug: bookshelf-rest-api | category: backend | difficulty: easy
-- rubric dimensions: 5
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_003',
    'system',
    'Bookshelf REST API',
    'bookshelf-rest-api',
    'Junior Backend Engineer interview. Build a small REST API from scratch with CRUD, filters, validation, persistence, and a test suite that would catch a regression next sprint.',
    '# Bookshelf REST API

Build a REST API for managing a personal bookshelf. You are starting from
an empty directory — pick your language and framework, scaffold the
project yourself, and design the storage layer however you like (SQLite,
a JSON file, or your favorite ORM all fine).

## What to build

The following endpoints, returning JSON:

- `POST /books` — body `{title, author, genre, year, status}` where
  `status` is one of `wishlist | reading | read`. Returns the created
  book with a generated id.
- `GET /books` — list. Supports `?status=...`, `?genre=...`,
  `?q=<title-substring>` (case-insensitive).
- `GET /books/{id}` — fetch one. 404 if missing.
- `PATCH /books/{id}` — partial update. Body may contain any subset of
  the fields above.
- `DELETE /books/{id}` — remove. 404 if missing.

The data must survive a process restart. Include a `tests/` directory
with tests covering each endpoint and at least one error path.

## What we care about

- The happy path works exactly as described, and the error responses
  make sense (validation problems are not 500s).
- The tests would catch a regression a teammate introduces next sprint.
- The code layout would not embarrass you in a code review.

## Out of scope

- Authentication.
- A frontend.
- Real-time / WebSockets.
- A "real" database — SQLite or a JSON file is fine.
',
    'easy',
    'backend',
    '["rest", "api", "backend", "testing"]',
    60,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Functional Correctness", "weight": 10, "description": "Every endpoint behaves as specified and persistence survives restart. **2/10**: Some endpoints work but list filters, PATCH, or DELETE are broken. **5/10**: All endpoints work in memory but state is lost on restart, or filters don''t combine. **8/10**: All endpoints work, filters compose correctly, restart-safe. **10/10**: Above + sensible edge cases (PATCH with unknown field rejected cleanly, case-insensitive search, status validation against the enum)."}, {"name": "Validation and Error Surfaces", "weight": 8, "description": "Bad input never produces a 500, and error responses are useful. **2/10**: Most validation errors return 500 or a stack trace. **5/10**: Validation returns 400 but the body is generic. **8/10**: Distinct status codes (400 validation, 404 missing, 409 conflict), structured error body with a field-level breakdown. **10/10**: Above + stable error_code field; no internal details leaked; missing required fields are caught at the boundary."}, {"name": "Test Coverage", "weight": 7, "description": "Tests would catch regressions on the contract, not just on the happy path. **2/10**: One or two smoke tests against a single endpoint. **5/10**: Happy path covered for all endpoints. **8/10**: Happy path + at least one error path per endpoint; isolated fixtures so order doesn''t matter. **10/10**: Above + parameterized tests over equivalence classes (e.g., boundary years, weird title strings)."}, {"name": "API Design", "weight": 6, "description": "URLs, methods, and responses follow REST conventions and are consistent. **2/10**: Endpoints use ad-hoc verbs (e.g., /addBook); responses inconsistent. **5/10**: REST conventions mostly followed; minor inconsistencies (e.g., status codes mixed). **8/10**: Consistent URL shape, methods, and response envelope; pagination on list if dataset grows. **10/10**: Above + OpenAPI / README documents the contract; error envelope documented; query semantics (combining filters) explained."}, {"name": "Code Quality and Layering", "weight": 5, "description": "A teammate can navigate the repo without a tour. **2/10**: Everything in one file; mixed routing and persistence logic. **5/10**: Some separation but storage calls leak into route handlers. **8/10**: Router / service / storage layers separated; types or schemas used consistently; no globals. **10/10**: Above + minimal but clear README; configuration via env vars; sensible logging."}]}',
    NULL,
    3.0,
    1,
    1
);

-- ============================================================
-- Q4: Idempotent ETL Pipeline with Schema Drift
-- slug: idempotent-etl-pipeline-with-schema-drift | category: data | difficulty: medium
-- rubric dimensions: 6
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_004',
    'system',
    'Idempotent ETL Pipeline with Schema Drift',
    'idempotent-etl-pipeline-with-schema-drift',
    'Mid Data Engineer interview. Generate sample CSVs with realistic drift and build a re-runnable pipeline that lands them in a clean table, rejects bad rows with reasons, and traces every row back to source.',
    '# Idempotent ETL Pipeline with Schema Drift

You are the first data engineer at a small analytics startup. Three
partners send you daily CSV exports of order events. Their schemas drift
without warning, files sometimes arrive twice, and once a week one file
arrives a day late. Your job is to land all of it in a clean `orders`
table that the analytics team can query.

You are starting from an empty directory. As part of your work,
**generate the sample CSVs yourself** — three partners, each with one
CSV per day for a week (7 days). Introduce realistic drift between
partners and across days: rename a column on day 3, change a price from
string to integer minor units on day 5, add an extra column on day 6
that earlier days don''t have. We will read both your generator and your
pipeline.

## What to build

A pipeline runnable as `python pipeline.py --run-date YYYY-MM-DD` that:

1. Reads each partner''s CSV for that date.
2. Normalizes each row to the `orders` table schema:
   `(order_id, partner, customer_email, amount_minor, currency, placed_at, ingested_at, source_file, run_id)`.
3. Loads to the target table (SQLite or Postgres, your choice)
   **idempotently** — re-running for the same date is a no-op (or, if
   the source data changed, updates cleanly).
4. Rejects bad rows to a `rejects` table with the original row + reason
   + source file + run_id.
5. Handles schema drift:
   - Renames (`customer_email` vs `email` vs `customerEmail`) via a
     mapping you control.
   - Type drift (`amount` as `"42.50"` vs `4250` vs `42.5`).
   - Late-arriving columns (additive) are tolerated; missing required
     columns are loud failures.
6. Emits metrics or a status row per run: rows in / out / rejected, per
   partner, plus duration.

## What we care about

- Re-running yesterday''s pipeline does not double-count.
- A 5GB file (you don''t need to provide one, but design for it) would
  not OOM your process.
- Three months from now, a fourth partner can be added without
  rewriting the core pipeline.

## Out of scope

- A real orchestrator (Airflow / Dagster); a CLI is fine.
- Dashboards.
- Real-time / streaming.
',
    'medium',
    'data',
    '["etl", "data-engineering", "pipeline", "idempotency"]',
    90,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Idempotency", "weight": 10, "description": "Re-running the same date must not duplicate or corrupt rows. **2/10**: Re-running creates duplicates. **5/10**: Idempotent via DELETE + INSERT \u2014 works but loses history during the window. **8/10**: Upsert keyed on (partner, business_key, run_date); no duplicates, no data loss. **10/10**: Above + handles late-arriving data correctly (yesterday''s file arriving today updates the right partition without disturbing other days)."}, {"name": "Schema Drift Handling", "weight": 9, "description": "Renames and type drift do not break the pipeline silently. **2/10**: Hardcoded column positions; any new or renamed column crashes the pipeline. **5/10**: Renames mapped in a config; missing columns produce nulls without flagging. **8/10**: Type coercion with explicit rules; mismatched types routed to rejects. **10/10**: Above + schema contract per partner; additive changes pass, breaking changes fail loudly with a clear diff."}, {"name": "Data Quality and Reject Handling", "weight": 8, "description": "Bad rows are captured, not lost or fatal. **2/10**: Bad rows crash the entire run. **5/10**: Bad rows skipped silently with no record. **8/10**: Rejects table with row + reason + source_file + run_id; queryable. **10/10**: Above + a reject-rate threshold that flags or alerts; sampling captured for drift analysis."}, {"name": "Lineage and Auditability", "weight": 7, "description": "Every row in the target traces back to its source. **2/10**: No source metadata persisted with rows. **5/10**: Each row tagged with the source filename only. **8/10**: Ingest timestamp, run_id, source row number, transformation version all persisted. **10/10**: Above + a query that reconstructs a row''s full processing history (which run wrote it, what transformations applied)."}, {"name": "Performance and Scalability", "weight": 6, "description": "The design would not collapse on a 5GB file. **2/10**: Loads entire CSV into memory; would OOM on a 5GB file. **5/10**: Streamed parsing but un-batched DB writes (one row, one INSERT). **8/10**: Streamed reads + bulk insert batches; indexes only on lookup paths, not every column. **10/10**: Above + parallelism per partner with configurable concurrency; throughput observable as a metric."}, {"name": "Operability", "weight": 6, "description": "An on-call engineer can tell what happened on any given run. **2/10**: Run-it-and-pray \u2014 no logging. **5/10**: Logs progress; run_id is at least surfaced. **8/10**: Per-run status row with metrics (rows in/out/rejected), retrievable. **10/10**: Above + a partial failure can be restarted from a checkpoint without reprocessing already-loaded rows."}]}',
    NULL,
    5.0,
    1,
    1
);

-- ============================================================
-- Q5: Multi-Tenant Feature Flag Service
-- slug: multi-tenant-feature-flag-service | category: platform | difficulty: medium
-- rubric dimensions: 6
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_005',
    'system',
    'Multi-Tenant Feature Flag Service',
    'multi-tenant-feature-flag-service',
    'Mid Platform Engineer interview. Build a feature-flag service from scratch with sticky percentage rollouts, an instant kill switch, tenant isolation, and a tamper-evident audit log.',
    '# Multi-Tenant Feature Flag Service

Build a small feature-flag service from scratch. Several customer
organizations call your service to decide whether to enable a feature
for a given user. Start from an empty directory and pick your language
and storage (SQLite is fine).

## Functional requirements

| Method | Path | Purpose |
|---|---|---|
| `POST` | `/tenants/{tenant}/flags` | Create or update a flag. Body: `{key, description, default, variants[], rollout}`. |
| `GET`  | `/tenants/{tenant}/flags` | List all flags for the tenant. |
| `POST` | `/tenants/{tenant}/flags/{key}/kill` | Instant kill switch — forces the flag to `off`, reversible. |
| `POST` | `/tenants/{tenant}/evaluate` | Body: `{subject_id, flags: [keys...]}`. Returns each flag''s resolved value for that subject. |
| `GET`  | `/tenants/{tenant}/audit?flag=...` | Paginated audit log of every change. |

`rollout` is one of:

- `{"type": "off"}` → always returns `default`.
- `{"type": "on"}` → always returns the first variant (or a configured
  value).
- `{"type": "percentage", "percent": 0..100}` → returns variant A for
  the first `percent`% of subjects (by stable hash), `default`
  otherwise.

## Hard rules

1. **Sticky bucketing.** A subject''s bucket is determined by a stable
   hash of `(tenant, flag_key, subject_id)`. As `percent` grows from 1
   to 100, a subject that was in the 1% bucket stays in the 5%, 10%,
   ..., 100% bucket. They never flap.
2. **Tenant isolation.** Tenant A''s flags, audit entries, and
   evaluation results are invisible to tenant B at every endpoint.
3. **Kill switch is instant.** A killed flag returns `off` for everyone
   on the next evaluation request and is recorded in the audit log.
   Unkill restores the prior rollout.
4. **Audit is append-only.** Every flag change records who, when,
   before/after, and the operation. Nothing in the audit log can be
   updated or deleted via the API.

## Out of scope

- A real auth layer; trust the `tenant` and a header like `X-Actor` for
  this exercise.
- A UI.
- Real-time push to clients (poll-based evaluation is fine).
',
    'medium',
    'platform',
    '["feature-flags", "multi-tenant", "platform", "rollout"]',
    90,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Sticky Bucketing Math", "weight": 10, "description": "Subjects do not flap as the rollout percentage grows. **2/10**: Random per request \u2014 same subject can get different answers from one second to the next. **5/10**: Hash-based but the hash is unstable (e.g., depends on Python''s per-process hash seed). **8/10**: Stable hash of (tenant, flag, subject_id); ramping percent 1 \u2192 100 strictly adds subjects, never removes. **10/10**: Above + math is correct under edge percentages (0 and 100 behave as documented); test demonstrates monotonic inclusion."}, {"name": "Tenant Isolation", "weight": 9, "description": "Tenant A cannot see, modify, or be billed for tenant B''s data. **2/10**: Tenant id passed but not enforced \u2014 cross-tenant reads succeed. **5/10**: Tenant filter on /flags and /evaluate but audit log or kill leaks across. **8/10**: All endpoints (including audit and kill) scoped to tenant; explicit cross-tenant test included. **10/10**: Above + tenant id is part of every storage key (not just a WHERE clause); no path returns another tenant''s data, even in error responses."}, {"name": "Kill Switch Semantics", "weight": 8, "description": "Kill switch is instant, reversible, and auditable. **2/10**: Kill endpoint exists but has no effect, or requires a redeploy. **5/10**: Kill toggles the flag but the rollout config is overwritten (un-kill is lossy). **8/10**: Kill is an overlay \u2014 original rollout config preserved; un-kill restores it; both states recorded in audit. **10/10**: Above + visible in next evaluation request without restart; rate-limit-friendly so a bad actor can''t flap a flag."}, {"name": "Audit Log Quality", "weight": 7, "description": "An on-call engineer can answer ''who changed what, when'' in one query. **2/10**: No audit log. **5/10**: Audit log exists but only records changes, not who or when. **8/10**: Append-only log with (actor, action, before, after, timestamp); paginated; per-flag filter. **10/10**: Above + tamper-evident (sequence number or hash chain); ordering stable across processes; never trimmed silently."}, {"name": "Evaluation Performance", "weight": 6, "description": "Evaluation stays fast as the flag count grows. **2/10**: Each /evaluate call does a full table scan per flag. **5/10**: Indexed lookups but evaluating N flags is N round trips. **8/10**: Single round-trip for the whole batch; bucketing math is O(1) per flag. **10/10**: Above + an in-memory cache with explicit invalidation on writes (and clear, documented staleness bounds)."}, {"name": "API Design and Operability", "weight": 5, "description": "Errors and logging are useful to the on-call engineer. **2/10**: All errors collapse to 400 with a generic message. **5/10**: Distinct status codes but no stable error_code; logs are unstructured. **8/10**: Structured logs include tenant, actor, flag key, request id; distinct error codes for unknown flag vs invalid rollout vs auth. **10/10**: Above + writes are idempotent (same payload, same key \u2192 same outcome); README documents the evaluation contract."}]}',
    NULL,
    5.0,
    1,
    1
);

-- ============================================================
-- Q6: Secrets Vault with Envelope Encryption
-- slug: secrets-vault-with-envelope-encryption | category: security | difficulty: medium
-- rubric dimensions: 6
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_006',
    'system',
    'Secrets Vault with Envelope Encryption',
    'secrets-vault-with-envelope-encryption',
    'Mid Security Engineer interview. Build a secrets vault from scratch with per-tenant KEKs, envelope encryption, scoped bearer tokens, an online key-rotation path, and a tamper-evident audit log.',
    '# Secrets Vault with Envelope Encryption

Build a small secrets-vault service from scratch. Customer applications
retrieve encrypted secrets through short-lived bearer tokens. Start from
an empty directory and pick your language. Use a real AEAD primitive
from the standard library or a well-known package (AES-GCM,
ChaCha20-Poly1305) — do **not** hand-roll cryptography.

## Functional requirements

| Method | Path | Purpose |
|---|---|---|
| `POST` | `/tenants` | Create a tenant. Generates a per-tenant KEK (key-encryption-key), stored wrapped by a single master key from env. |
| `POST` | `/tenants/{tenant}/secrets` | Body: `{name, value}`. Generate a fresh DEK, encrypt the value with the DEK, wrap the DEK with the tenant''s KEK, persist the wrapped blob. |
| `GET`  | `/tenants/{tenant}/secrets/{name}` | Decrypt and return the plaintext value if the caller''s bearer token is valid AND scoped to `{name}` (or to `*`). |
| `DELETE` | `/tenants/{tenant}/secrets/{name}` | Soft-delete; secret is unreadable but the audit trail remains. |
| `POST` | `/tenants/{tenant}/rotate-kek` | Generate a new KEK; re-encrypt every DEK for the tenant under the new KEK; retire the old KEK. Must not require downtime or invalidate existing tokens. |
| `POST` | `/tokens` | Issue a bearer token. Body: `{tenant, scopes[], ttl_seconds}`. |
| `GET`  | `/audit?tenant=...` | Paginated immutable audit log. |

## Hard rules

1. **Crypto correctness.** AEAD only. A fresh nonce / IV per encryption,
   never reused. Envelope encryption is real — DEKs are never persisted
   unwrapped, never written to logs.
2. **Authorization.** Every read checks the token''s scope against the
   requested secret name. Token comparison is time-constant. Tokens are
   bearer credentials — they never appear in URLs or logs.
3. **No leakage on failure paths.** Secret values never appear in URLs,
   logs, error responses, or stack traces — not even partially, not
   even on authentication failure.
4. **Audit is tamper-evident.** Every read, write, rotation, and failed
   authorization attempt is recorded with `(timestamp, tenant,
   subject, action, secret_name, outcome)` in a sequenced or
   hash-chained append-only log.
5. **Rotation is online.** A `rotate-kek` that crashes halfway must
   leave the vault readable — never bricked. After it completes, the
   old KEK can be retired.

## Out of scope

- A real HSM or KMS — store the master key in an env var.
- TLS — assume a sidecar terminates it.
- A UI.
- Token issuance UX (admin or human auth flow); a simple endpoint that
  mints a token is enough.
',
    'medium',
    'security',
    '["security", "cryptography", "vault", "key-management"]',
    90,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Crypto Correctness", "weight": 10, "description": "AEAD is used correctly; envelope encryption is real. **2/10**: Hand-rolled crypto, ECB mode, raw block cipher, or static IV. **5/10**: AEAD used but nonces are reused, or DEKs persisted unwrapped, or no associated data binding. **8/10**: AEAD with unique nonces per encryption; DEKs always wrapped before storage; KEKs derived/loaded from a single master. **10/10**: Above + associated data binds ciphertext to context (tenant + secret name); nonce strategy documented and demonstrably collision-free."}, {"name": "Authorization and Token Hygiene", "weight": 9, "description": "Every read is authorized and tokens are handled like the bearer credentials they are. **2/10**: Authorization absent or trivially bypassable (e.g., role passed in body, no validation). **5/10**: Token checked but compared with `==` (timing leak); scopes checked sometimes but not on every read. **8/10**: Time-constant comparison; scope enforced on every read; tokens never appear in logs or error responses. **10/10**: Above + token rotation works under load; TTL respected exactly; expired-token responses do not leak whether the secret exists."}, {"name": "Secret Material Hygiene", "weight": 8, "description": "Plaintext secret values exist only at the moments they must. **2/10**: Plaintext secrets logged or echoed in error responses. **5/10**: Secrets not logged on the happy path but leak through stack traces or 500 responses. **8/10**: Plaintext appears only in the GET response body; not in URLs, logs, or any error path. **10/10**: Above + DEKs cleared from memory after use where the language permits; debug endpoints, if any, are off by default and clearly gated."}, {"name": "Audit Tamper-Evidence", "weight": 7, "description": "An attacker who reaches the DB cannot quietly cover their tracks. **2/10**: No audit log. **5/10**: Audit log exists but is unsequenced and easily mutable; no record of failed authz attempts. **8/10**: Append-only with sequence numbers; every read, write, rotation, and failed authz attempt recorded. **10/10**: Above + hash-chained with prev_hash \u2192 hash; a verification utility detects the first divergence; canonical entry serialization is stable across processes."}, {"name": "Key Rotation Safety", "weight": 7, "description": "Rotation never bricks the vault, even mid-flight. **2/10**: No rotation endpoint, or rotation deletes the old KEK before re-encrypting. **5/10**: Rotation works on the happy path but a crash mid-rotation leaves some secrets unreadable. **8/10**: Crash mid-rotation leaves all secrets readable (resumable from a checkpoint); old KEK retired only after every DEK is re-wrapped. **10/10**: Above + rotation is online (no read downtime); existing tokens stay valid; rotation is observable via the audit log."}, {"name": "API Design and Operability", "weight": 5, "description": "Errors and structure do not leak information or confuse the caller. **2/10**: Inconsistent status codes; error bodies expose internals. **5/10**: Distinct codes, but the difference between ''wrong scope'' and ''no such secret'' is observable to an attacker. **8/10**: Distinct codes with stable error_code field; authz failures return the same response regardless of whether the secret exists. **10/10**: Above + structured logs with request id, tenant, actor; rate-limit on token issuance and on failed authz; README documents the threat model."}]}',
    NULL,
    5.0,
    1,
    1
);

-- ============================================================
-- Q7: Production RAG Service with Eval Harness & Cost Guardrails
-- slug: production-rag-service-with-eval-harness-cost-guardrails | category: ai | difficulty: hard
-- rubric dimensions: 8
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_007',
    'system',
    'Production RAG Service with Eval Harness & Cost Guardrails',
    'production-rag-service-with-eval-harness-cost-guardrails',
    'Applied AI / RAG Engineer interview. Ship a multi-tenant retrieval-augmented service with isolation, cost budgets, semantic caching, and a real eval harness. Senior signal: tenant isolation, idempotent ingest, hallucination refusal, eval rigor.',
    '# Multi-Tenant RAG Service with Eval Harness and Cost Guardrails

Build **Helix**, a hosted Retrieval-Augmented Generation service that
several customer organizations call from their own products. You are
starting from an empty directory — scaffold the service yourself in
your language of choice.

Do **not** call real external APIs. As part of your work, **write your
own deterministic stub embedding client and stub LLM client** (e.g.,
a hash-based embedding, a template-based "LLM" that pastes retrieved
context into a fixed response). Also generate a small in-repo corpus
of ~30 short documents across 3 tenants and an eval set of ~5
`(query, gold_answer)` pairs per tenant.

## Functional requirements

| Method | Path | Purpose |
|---|---|---|
| `POST` | `/tenants/{tenant_id}/docs` | Upsert a document. Body: `{doc_id, version, text}`. Chunk, embed, index. |
| `DELETE` | `/tenants/{tenant_id}/docs/{doc_id}` | Soft-delete document and all its chunks. |
| `POST` | `/tenants/{tenant_id}/ask` | Body: `{query}`. Returns `{answer, citations[], confidence, cached, cost_usd}`. |
| `POST` | `/tenants/{tenant_id}/eval/run` | Runs the stored eval set, returns per-metric scores. |
| `GET`  | `/tenants/{tenant_id}/usage` | Returns today''s spend and remaining daily budget. |

## Non-functional requirements that we care about

1. **Tenant isolation is a hard requirement.** A query from tenant A
   must never retrieve, cache-hit, or be billed against tenant B. Treat
   this as a security boundary, not a UX concern.
2. **Per-tenant daily USD budget**, configurable per tenant in a config
   file you control. When the budget is exhausted the service must
   return `429` with a `Retry-After` header. Cache hits are free.
3. **Semantic cache** for `/ask`. Identical or near-identical queries
   from the same tenant should not re-call the LLM.
4. **Refuse to hallucinate.** If retrieval confidence is below a
   threshold, return a structured `"I don''t know"` response with
   `confidence: "low"` rather than a fluent but ungrounded answer.
5. **Eval harness reports separate metrics**: groundedness, answer
   relevance, context precision, context recall. A single number is not
   enough.
6. **Resilience.** If the LLM stub raises (you should add a flag to
   make it raise on demand), the vector store is slow, or indexing
   partially fails, the service degrades rather than 500s on the user.

## Out of scope

- Real authentication; trust the `tenant_id` in the URL for this
  exercise.
- A real vector database; an in-memory store is fine.
- A frontend.

## What we will look at

We will read your code, run your `/ask` and `/eval/run` endpoints, and
try to find a way to leak data across tenants or get billed past the
cap. Write the kind of code you would expect to be paged about at 3am.
',
    'hard',
    'ai',
    '["ai", "rag", "llm", "multi-tenant"]',
    120,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Tenant Isolation", "weight": 10, "description": "Cross-tenant data leakage is treated as a security boundary, not a UX concern. **2/10**: Tenant filter applied only in app code after vector search; cache shared across tenants. **5/10**: Tenant filter at the index layer for /ask, but cache or eval endpoints not tenant-scoped. **8/10**: Filter at index + cache scoping + eval/usage endpoints all scoped to the tenant. **10/10**: No path (errors, eval runs, partial responses) returns another tenant''s content; explicit cross-tenant test included."}, {"name": "Idempotent Ingestion and Re-embed Safety", "weight": 8, "description": "Re-ingesting documents does not duplicate vectors or leave phantoms. **2/10**: Re-posting the same doc duplicates chunks; no version concept. **5/10**: (doc_id, version) keying prevents most duplicates, but partial failure leaves orphans. **8/10**: Upsert by (doc_id, version); prior chunks soft-deleted on update; partial failures recoverable. **10/10**: Embed + index atomic (or saga with compensating delete); idempotency exercised by a test."}, {"name": "Cost Guardrails and Backpressure", "weight": 9, "description": "Per-tenant USD budget enforced before the LLM call, race-safe. **2/10**: Budget checked after the LLM call, or not at all. **5/10**: Budget checked before the call but with a time-of-check / time-of-use race window. **8/10**: Atomic decrement; 429 with Retry-After; cache hits do not consume budget. **10/10**: Per-tenant kill switch without redeploy; concurrent calls cannot bypass the cap; budget burn observable."}, {"name": "Retrieval Quality Engineering", "weight": 8, "description": "Retrieval is engineered to support refusal, not just nearest-neighbor search. **2/10**: Naive fixed-character chunks; raw top-k embeddings returned as-is. **5/10**: Sentence-boundary chunking and basic top-k dense retrieval. **8/10**: MMR or re-rank for diversity; confidence threshold triggers ''I don''t know'' instead of fluent fiction. **10/10**: Hybrid (BM25 + dense) or learned re-rank; citations validated against retrieved chunks."}, {"name": "Eval Harness Rigor", "weight": 7, "description": "Eval distinguishes retrieval quality from generation quality so regressions are diagnosable. **2/10**: A single accuracy / pass-rate number. **5/10**: Two separate metrics, typically groundedness + relevance. **8/10**: All four reported separately: groundedness, answer relevance, context precision, context recall. **10/10**: Eval set versioned; regression detection across runs; basic contamination check (golden answers not memorized from corpus)."}, {"name": "Semantic Cache Correctness", "weight": 7, "description": "Cache must not poison future answers or leak across tenants. **2/10**: No cache, or cache keyed only by raw query string. **5/10**: Cache keyed by query + tenant; invalidated on doc change. **8/10**: Model and retrieval config included in key; low-confidence answers are NOT cached. **10/10**: Stable-on-doc-update strategy with TTL; cache size bounded; stale flag surfaced when used."}, {"name": "Failure Mode Handling", "weight": 8, "description": "Degrade rather than 500 when the LLM or vector store misbehaves. **2/10**: LLM error or vector-store timeout returns a 500 with the stack trace. **5/10**: Errors caught and surfaced as a generic 502; no backoff or retry logic. **8/10**: Circuit breaker / backoff on the LLM; degrades to cached or partial response with a clear flag. **10/10**: Structured error codes; no PII / raw query in error logs; idempotent retries that respect the budget."}, {"name": "Code Structure and API Ergonomics", "weight": 5, "description": "Code is shaped so the next engineer can swap a component without a rewrite. **2/10**: All logic in one file; no types; secrets present in code. **5/10**: Reasonable layout; typed request/response models; basic logging. **8/10**: Retriever, ranker, generator, cache behind interfaces; structured logs with tenant_id + trace_id. **10/10**: README names the next production concern; secrets never appear in logs/errors; LLM is genuinely pluggable."}]}',
    NULL,
    10.0,
    1,
    1
);

