-- Q8: Multi-Currency Wallet Ledger with Idempotent Transfers
-- slug: multi-currency-wallet-ledger-with-idempotent-transfers | category: backend | difficulty: hard
-- rubric dimensions: 9
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_008',
    'system',
    'Multi-Currency Wallet Ledger with Idempotent Transfers',
    'multi-currency-wallet-ledger-with-idempotent-transfers',
    'Senior Backend Engineer interview. Build the core double-entry ledger for a multi-currency wallet: atomic transfers, race-safe negative-balance enforcement, idempotency, compensating reversals, and a tamper-evident audit chain.',
    '# Multi-Currency Wallet Ledger with Idempotent Transfers

Build the core ledger for **Stack**, a multi-currency wallet product.
The ledger is the source of truth for every dollar, peso, and satoshi
the company is responsible for. Money lost or invented here is a
front-page incident.

You are starting from an empty directory. Pick your language; use
SQLite or Postgres for storage.

## Functional requirements

Expose an HTTP service with the following endpoints:

| Method | Path | Purpose |
|---|---|---|
| `POST` | `/accounts` | `{owner_id, currency}` → creates an account. |
| `POST` | `/transfers` | `{source_account_id, dest_account_id, amount_minor, currency}`. Header: `Idempotency-Key`. |
| `POST` | `/transfers/{id}/reverse` | `{reason}`. Creates a compensating entry; original stays intact. |
| `GET`  | `/accounts/{id}/balance` | Current balance for the account. |
| `GET`  | `/accounts/{id}/statement?from=...&to=...` | Paginated journal entries. |
| `GET`  | `/admin/integrity` | Runs reconciliation: per currency, sum(debits) == sum(credits). |

Seed a `currencies` table that declares decimal places per currency
(`USD: 2`, `JPY: 0`, `BTC: 8`). Amounts are integer **minor units** at
the API boundary and in storage.

Some accounts have `credit_line_minor` > 0 (overdraft allowance). All
others must reject any transfer that would make the balance negative.

## Hard rules

1. Every transfer creates **two journal entries**: a debit on the
   source and a credit on the destination. Both succeed or both fail.
   The ledger invariant — total debits == total credits, per currency —
   must hold at all times.
2. **Cross-currency transfers are rejected.** FX is out of scope.
3. **Idempotency-Key** is required on `/transfers` and
   `/transfers/.../reverse`.
   - Same key, same payload, within 24h → return the original
     response.
   - Same key, different payload → `409 Conflict`.
   - Same key, two concurrent requests → exactly one creates the
     transfer.
4. **No destructive edits.** Refunds and corrections are compensating
   entries that reference the original.
5. **Balance is derived from the journal**, not stored as the source
   of truth. You may add a cached running total as an optimization,
   but the journal must be authoritative and the integrity endpoint
   must verify it.
6. **Audit log is tamper-evident.** Each journal entry stores
   `prev_hash` and `hash`, forming a chain. A utility that detects
   tampering is part of the deliverable.

## Out of scope

- Authentication (trust the `owner_id` in the body).
- Real money movement / banking integrations.
- A UI.

## What we will do to it

We will hammer `/transfers` concurrently with the same key, send a
flurry of small transfers against a single hot account, run
`/admin/integrity` after every test, and try to find a path that
breaks debit/credit equality or lets a non-credit-line account go
negative.
',
    'hard',
    'backend',
    '["fintech", "ledger", "double-entry", "idempotency"]',
    120,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Double-Entry Invariants", "weight": 10, "description": "Sum(debits) == sum(credits) per currency at every moment, recoverable from the journal alone. **2/10**: Transfer creates one row (a delta); no separate debit/credit entries. **5/10**: Two journal entries per transfer but written in separate transactions, opening a window of inconsistency. **8/10**: Both legs atomic in one DB transaction; /admin/integrity verifies the invariant from the journal. **10/10**: Balance always reconstructed from journal in tests; cached running totals (if any) clearly marked as derived and reconciled."}, {"name": "Idempotency Correctness", "weight": 9, "description": "Same Idempotency-Key must produce at most one transfer, even under concurrent retries. **2/10**: Idempotency-Key ignored, or used only to cache the response AFTER the side effect. **5/10**: Same key returns prior response, but check-then-insert allows duplicate transfers under concurrency. **8/10**: Idempotency record stored with a payload hash BEFORE side effects; unique constraint prevents double creation; 409 on payload mismatch. **10/10**: Concurrent stress test passes; TTL documented; key required at the request boundary, not optional."}, {"name": "Money Representation", "weight": 8, "description": "Money is integer minor units everywhere; cross-currency is rejected, not silently converted. **2/10**: Amounts as floats anywhere in API, storage, or arithmetic. **5/10**: Integer minor units in storage but float conversion at API edges. **8/10**: Integer minor units end-to-end; currency on every entry; mixed-currency transfers rejected at the request boundary. **10/10**: Decimal places per currency sourced from the currencies table (not hardcoded); rounding policy or ''no division'' explicitly documented."}, {"name": "Concurrency and Negative Balance Safety", "weight": 9, "description": "Two concurrent transfers from the same near-empty account cannot both succeed. **2/10**: Negative balance check is read-then-write in app code; race-vulnerable. **5/10**: Some locking exists, but coarse-grained or held across slow operations. **8/10**: Row lock / SELECT FOR UPDATE / conditional update; concurrent transfers cannot both pass the credit line. **10/10**: Isolation level chosen with documented reasoning; hot-account contention handled or trade-off explicitly called out."}, {"name": "Reversal Semantics", "weight": 7, "description": "Reversals are compensating entries; the original is never mutated. **2/10**: Reversal mutates the original entry (destructive edit). **5/10**: Reversal creates a new entry but does not reference the original. **8/10**: Compensating debit+credit pair references the original; original stays queryable; double-reverse can''t produce net-positive funny state. **10/10**: Statements show both original and reversal cleanly; chains of reversals/re-reversals handled."}, {"name": "Audit Tamper-Evidence", "weight": 6, "description": "The journal is hash-chained and tampering is detectable. **2/10**: No hashing at all. **5/10**: Hash per entry but not chained (no prev_hash linkage). **8/10**: prev_hash + canonical entry payload \u2192 hash; a verification utility finds the first divergence. **10/10**: Canonical serialization stable across processes (ordered keys, fixed encoding); cost trade-off (on-write vs rebuild) documented."}, {"name": "Statements and As-Of Queries", "weight": 7, "description": "Statements survive high cardinality and concurrent writes. **2/10**: Statements truncate to N most recent or load everything into memory. **5/10**: Pagination via OFFSET (skips rows under concurrent inserts). **8/10**: Cursor-based pagination stable under writes; as-of-timestamp queries work. **10/10**: Candidate articulates scaling strategy at 1B rows (periodic snapshots, partitioning, materialized aggregates)."}, {"name": "Operational Concerns", "weight": 6, "description": "A killed process between debit and credit cannot leave the ledger inconsistent. **2/10**: Process crash mid-transfer leaves debit without credit. **5/10**: Single transaction prevents inconsistency, but no outbox for downstream events. **8/10**: Transactional outbox for downstream notifications; reconciliation endpoint exists. **10/10**: Outbox publisher with retry/backoff and ordering; reconciliation runs as a job and surfaces drift."}, {"name": "API Design and Error Surfaces", "weight": 5, "description": "Errors are machine-parseable and meaningful, not generic 400s. **2/10**: Idempotency-Key in body; all errors collapse to 400. **5/10**: Idempotency-Key in header; distinct codes for insufficient funds vs validation. **8/10**: Stable error_code field; currency mismatch and idempotency conflict have distinct, documented codes. **10/10**: OpenAPI / README documented; cursor pagination on /statement; errors carry remediation hints."}]}',
    NULL,
    10.0,
    1,
    1
);

-- ============================================================
-- Q9: Zero-Downtime Schema Migration & Progressive Rollout
-- slug: zero-downtime-schema-migration-progressive-rollout | category: platform | difficulty: hard
-- rubric dimensions: 9
-- ============================================================

INSERT OR IGNORE INTO challenges
    (id, created_by, title, slug, description, problem_statement_md,
     difficulty, category, tags, time_limit_minutes, test_suite,
     scoring_config, starter_files, max_budget_usd, is_public, is_featured)
VALUES
(
    'quality_challenge_009',
    'system',
    'Zero-Downtime Schema Migration & Progressive Rollout',
    'zero-downtime-schema-migration-progressive-rollout',
    'Staff Platform / SRE Engineer interview. Migrate a hot, free-text column to a normalized FK on a running service with sustained traffic. Expand/contract, dual-write, sticky percentage rollout, SLO-burn-rate alerting, and a rollback plan that survives a half-finished backfill.',
    '# Zero-Downtime Schema Migration with Progressive Rollout

Build **Orderly**, a small HTTP service serving `/orders` endpoints,
then migrate it from a free-text `shipping_address` column to a
normalized `shipping_address_id` FK on a separate `addresses` table —
all while it serves sustained traffic with zero downtime.

You are starting from an empty directory. Build everything from
scratch: the service in your language of choice, your storage layer
(SQLite or Postgres), a multi-process or docker-compose setup that
runs N replicas, and a small load generator that drives sustained
50 RPS of mixed read/write against `/orders` during the cutover.

Seed ~100k rows locally; the production scenario is ~50M rows. You
are paged if p99 latency exceeds 300ms during the cutover, or if any
order is lost or pointed at the wrong address.

## What you ship

1. **Expand/contract migration broken into discrete, reversible
   phases.** Each phase is a separate commit and a separate deploy.
   `python migrate.py phase=N` applies phase N;
   `phase=N --rollback` rolls it back.
2. **Application code that supports the in-between states:**
   - Phase 2 writes both `shipping_address` and `shipping_address_id`.
   - Phase 3 reads `shipping_address_id` if present, else
     `shipping_address`.
   - Phase 5 stops writing to `shipping_address`.
   - Phase 6 drops `shipping_address`.
3. **A backfill job** that copies existing free-text into normalized
   rows, restartable from a checkpoint, throttled to a configurable
   rows/sec.
4. **A feature flag** controlling the read path''s percentage shift
   from old to new: 0% → 1% → 10% → 50% → 100%. The flag is sticky
   per user_id (or order_id), not random per request. Flag store
   outage must not flip behavior randomly.
5. **Health checks**: `/livez` and `/readyz` are distinct. Graceful
   shutdown drains in-flight requests and deregisters from the LB
   before the process exits.
6. **An SLO + alert recipe** in `docs/slo.md`: define the SLO, the
   error budget, and the burn-rate alerts you would actually page on.
   Include the PromQL.
7. **A runbook** in `docs/runbook.md` covering: how to roll back each
   phase, what ''stuck'' looks like, and the dashboards you would open
   during the cutover.

A Prometheus + Grafana stack is **optional**. If you skip it, describe
in `docs/observability.md` exactly which metrics you would expose and
what your dashboard would show during the cutover.

Run your load generator during the migration. Show us — via metrics
endpoints, logs, or your own status output — that p99 holds, error
rate stays inside your error budget, and the dual-write divergence
counter stays at zero (or be explicit about why it doesn''t).

## Out of scope

- A real Kubernetes cluster — docker-compose or multiple local
  processes is fine.
- A production-grade flag service — a file or env var with a small
  wrapper is fine, but it must obey the requirements above.
- Authentication.

## What we will look at

We will read your phase commits in order and ask: could any single
phase be safely deployed to one replica while the others are still on
the prior version? If the answer is no for any phase, the migration is
unsafe.
',
    'hard',
    'platform',
    '["sre", "migrations", "zero-downtime", "platform"]',
    120,
    NULL,
    '{"profile": "spec_heavy", "rubric": [{"name": "Expand/Contract Discipline", "weight": 10, "description": "Every phase can be deployed to one replica while the others are still on the prior version. **2/10**: Single migration that renames the column and changes the code in one commit. **5/10**: Two phases (add + drop) but the new column is read before the backfill is complete. **8/10**: 5+ phases each independently deployable; schema additions precede code reads; old column dropped only after burn-in. **10/10**: Each phase reversible in code AND schema; candidate explains why a single-shot rename breaks mixed-version replicas."}, {"name": "Backfill Safety", "weight": 8, "description": "Backfill is restartable, throttled, and never holds a long transaction on a hot range. **2/10**: Single UPDATE statement covering all rows; locks the table. **5/10**: Batched but not restartable; long transactions per batch. **8/10**: Resumes from a persisted checkpoint; throttled rows/sec; bounded transactions; idempotent on re-run. **10/10**: Adaptive throttle (replication-lag aware); observable progress and ETA; no thundering-herd on hot ranges."}, {"name": "Dual Read/Write Correctness", "weight": 9, "description": "Old and new columns never diverge during the transition. **2/10**: Writes go only to the new column during transition; old replicas lose data. **5/10**: Both columns written but in separate statements (a crash leaves them inconsistent). **8/10**: Both columns written in a single transaction; inserts during backfill populate both; divergence counter emitted. **10/10**: Read path resolves consistently (new if present, else old); divergence counter gates the cutover percentage."}, {"name": "Progressive Rollout and Feature Flags", "weight": 8, "description": "Rollout is sticky per user and fails closed. **2/10**: Hard-coded boolean flag toggled at deploy time. **5/10**: Percentage rollout but random per request (flaps the user between code paths). **8/10**: Stable hash per user/order; flag store outage fails closed to prior behavior; kill switch exists. **10/10**: Rollout percentage exported as a metric; bucket distribution observable; gradual ramp scriptable."}, {"name": "Health Check Semantics", "weight": 7, "description": "Liveness and readiness mean different things; shutdown drains. **2/10**: Single /health endpoint; returns 200 if the process is alive. **5/10**: /livez and /readyz distinct, but readyz coupled to non-critical dependencies. **8/10**: livez reflects process alive only; readyz gated on critical deps; graceful shutdown drains in-flight. **10/10**: LB deregistration before shutdown; drain timeout justified with reasoning; readyz reflects flag store availability."}, {"name": "SLO-Driven Alerting", "weight": 7, "description": "Pages fire on error budget burn rate, not raw thresholds, and the PromQL actually works. **2/10**: Alerts fire on any 5xx response. **5/10**: Threshold alerts (e.g., error rate > 1% for 5 minutes) at a single window. **8/10**: Multi-window multi-burn-rate alerts per Google SRE workbook; p95 and p99 tracked, never the average. **10/10**: PromQL is correct and would fire as intended; routing/severity tiers defined; synthetic vs real-traffic distinction."}, {"name": "Observability During Cutover", "weight": 7, "description": "A single dashboard answers ''is the cutover healthy?'' **2/10**: One dashboard with raw error count. **5/10**: Phase indicator and error rate visible but no dual-write divergence metric. **8/10**: Phase, rollout %, divergence counter, backfill progress all on one dashboard; logs include phase id + bucket. **10/10**: Per-code-path latency; bucket-distribution chart; a single ''cutover health'' panel covers all gates."}, {"name": "Rollback Plan and Blast Radius", "weight": 8, "description": "Rollback works even if the backfill is partway through. **2/10**: ''Revert the deploy'' is the entire plan. **5/10**: Per-phase rollback documented but unsafe if backfill is partial. **8/10**: Per-phase rollback is safe at any backfill state; irreversible ops (DROP) gated by manual confirm + burn-in. **10/10**: Runbook names dashboards to watch during rollback; rollback path validated in a staging dry run."}, {"name": "Operational Hygiene", "weight": 5, "description": "The runbook works for the person paged at 3am. **2/10**: Secrets in code; no logs. **5/10**: Env vars for secrets; unstructured logs. **8/10**: Structured logs with trace ids; runbook written for the on-call pager. **10/10**: docker-compose comes up clean from a fresh clone; README walks through the cutover end-to-end."}]}',
    NULL,
    10.0,
    1,
    1
);

